import React from 'react';
import { Banknote } from 'lucide-react';
import ProgressBar from '../components/ProgressBar';
import { formatCurrency } from '../helpers/helpers';

export default function GoalsScreen({ goals, setModal, setSelectedGoal }) {
  return (
    <div className="pb-24 animate-fade-in">
      <header className="px-6 pt-12 pb-6 flex justify-between items-center bg-white sticky top-0 z-10">
        <h1 className="text-2xl font-bold text-gray-800">Goals</h1>
        <button onClick={()=>setModal('addGoal')} className="bg-emerald-600 text-white py-2 px-4 rounded-2xl font-bold hover:bg-emerald-700 transition-colors">
          Add Goal
        </button>
      </header>

      <div className="px-6 space-y-4 mt-4">
        {goals.length === 0 && <p className="text-gray-400">No goals yet. Click "Add Goal" to create one.</p>}
        {goals.map(goal => (
          <div key={goal.id} onClick={() => setSelectedGoal(goal)} className="bg-white p-4 rounded-2xl border border-gray-50 cursor-pointer hover:bg-gray-50 transition-colors">
            <div className="flex justify-between items-center mb-2">
              <h2 className="font-bold text-gray-800">{goal.title}</h2>
              <span className="text-2xl">{goal.icon}</span>
            </div>
            <ProgressBar current={goal.current} target={goal.target} color={goal.color} />
            <p className="text-gray-500 text-sm mt-2">${formatCurrency(goal.current)} / ${formatCurrency(goal.target)}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
